<div class="card"><div class="table-responsive"><table class="table table-hover mb-0"><tr><th>Siswa</th><th>Tugas</th><th>Kursus</th><th>File/Link</th><th>Waktu</th><th>Nilai</th><th>Aksi</th></tr><?php $__empty_1 = true; $__currentLoopData = $submissions; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $submission): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); $__empty_1 = false; ?><tr><td><?php echo e($submission->student->name); ?></td><td><?php echo e($submission->assignment->title); ?></td><td><?php echo e($submission->assignment->course->name); ?></td><td><?php echo e($submission->file_path); ?></td><td><?php echo e(optional($submission->submitted_at)->format('d/m/Y H:i')); ?></td><td><?php echo e($submission->score ?? 'Belum dinilai'); ?></td><td class="d-flex gap-1"><a class="btn btn-sm btn-info" href="<?php echo e(route($role.'.submissions.show',$submission)); ?>">Detail</a><?php if(in_array($role,['admin','guru'])): ?><a class="btn btn-sm btn-warning" href="<?php echo e(route($role.'.grades.edit',$submission)); ?>">Nilai</a><?php endif; ?> <?php if($role==='siswa'): ?><form method="POST" action="<?php echo e(route('siswa.submissions.destroy',$submission)); ?>" onsubmit="return confirm('Hapus submission?')"><?php echo csrf_field(); ?> <?php echo method_field('DELETE'); ?><button class="btn btn-sm btn-danger">Hapus</button></form><?php endif; ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_1): ?><tr><td colspan="7" class="text-center">Belum ada submission.</td></tr><?php endif; ?></table></div></div><div class="mt-3"><?php echo e($submissions->links()); ?></div>
